record.field:
for record in records:
    if record.x_studio_standard_rule or not record.x_studio_pos_product_category_ids:
        record['push_domain'] = ''
        break;
    domain = [("product_id.pos_categ_ids", "in", record.x_studio_pos_product_category_ids.ids)]
    record['push_domain'] = domain

for record in records:
    if record.product_selectable:
        record.write({'x_studio_automatic_activation_on_product': False})
    else:
        record.write({'x_studio_automatic_activation_on_product': True})

for recrod in records:
    if record.picking_type_id and record.picking_type_id.x_studio_overrule_customer_location:
        record.write({
            "location_dest_id": record.picking_type_id.default_location_dest_id.id
        })
